#!/usr/bin/env node
// Signs an adapter definitions JSON file and writes src/local-bundle.ts.
// Usage: node scripts/sign-bundle.mjs <definitions-json> <signing-key-json>

import { readFile, writeFile } from "node:fs/promises";
import path from "node:path";
import { fileURLToPath } from "node:url";

const [, , definitionsPath, signingKeyPath] = process.argv;

if (!definitionsPath || !signingKeyPath) {
  console.error(
    "Usage: node scripts/sign-bundle.mjs <definitions-json> <signing-key-json>",
  );
  process.exit(1);
}

function encodeBase64(buffer) {
  return Buffer.from(buffer).toString("base64");
}

function decodeBase64(value) {
  return Buffer.from(value, "base64");
}

const definitionsRaw = await readFile(definitionsPath, "utf8");
const definitionsJson = JSON.parse(definitionsRaw);

const bundle = {
  ...definitionsJson,
  generatedAt: new Date().toISOString(),
};

const payload = JSON.stringify(bundle);

const signingKeyRaw = await readFile(signingKeyPath, "utf8");
const signingKey = JSON.parse(signingKeyRaw);

const privateKey = await globalThis.crypto.subtle.importKey(
  "pkcs8",
  decodeBase64(signingKey.privateKey),
  { name: "Ed25519" },
  false,
  ["sign"],
);

const signatureBuffer = await globalThis.crypto.subtle.sign(
  { name: "Ed25519" },
  privateKey,
  new TextEncoder().encode(payload),
);

const output = `// Generated by scripts/sign-bundle.mjs. Do not edit manually.
import type { SignedAdapterBundle } from "./signature";

export const LOCAL_SIGNED_BUNDLE: SignedAdapterBundle = {
  payload: ${JSON.stringify(payload)},
  signature: {
    keyId: ${JSON.stringify(signingKey.keyId)},
    algorithm: "Ed25519",
    signature: ${JSON.stringify(encodeBase64(signatureBuffer))},
  },
};
`;

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const outputPath = path.join(__dirname, "..", "src", "local-bundle.ts");

await writeFile(outputPath, output, "utf8");

console.error(`Signed bundle written to ${outputPath}`);
